from google_adk import AgentSession
from collections import defaultdict

def detect_tool_loops(session: AgentSession, max_calls=5):
    tool_history = defaultdict(int)
    for step in session.execution_history:
        if hasattr(step, 'tool_calls'):
            for tool_call in step.tool_calls:
                tool_key = f'{tool_call.function_name}:{tool_call.args}'
                tool_history[tool_key] += 1
                if tool_history[tool_key] > max_calls:
                    return {'loop_detected': True, 'tool': tool_key}
    return {'loop_detected': False}

def detect_delegation_cycles(workflow):
    visited = set()
    def dfs(agent_id):
        if agent_id in visited:
            return True  # Cycle detected
        visited.add(agent_id)
        for delegation in workflow.get_delegations(agent_id):
            if dfs(delegation.target_agent):
                return True
        visited.remove(agent_id)
        return False

    for agent in workflow.agents:
        if dfs(agent.id):
            return {'cycle_detected': True, 'agent': agent.id}
    return {'cycle_detected': False}

def detect_state_bloat(session):
    tool_responses = [msg for msg in session.messages 
                     if hasattr(msg, 'tool_response')]
    if len(tool_responses) > 50:
        return {
            'bloat_detected': True,
            'response_count': len(tool_responses),
            'tokens_estimate': sum(len(str(r)) for r in tool_responses)
        }
    return {'bloat_detected': False}

