from google_adk import before_agent_callback

@before_agent_callback
def dedupe_tool_calls(ctx):
    seen_tools = ctx.session.get('seen_tools', set())
    filtered_calls = []
    for tool_call in ctx.proposed_tool_calls:
        tool_key = f'{tool_call.function_name}:{tool_call.args}'
        if tool_key not in seen_tools:
            seen_tools.add(tool_key)
            filtered_calls.append(tool_call)
    ctx.session['seen_tools'] = seen_tools
    ctx.tool_calls = filtered_calls

class CircuitBreakerAgent:
    def __init__(self):
        self.delegation_depth = 0
        self.max_depth = 3

    @before_agent_callback
    def check_delegation(self, ctx):
        if ctx.is_delegation and self.delegation_depth >= self.max_depth:
            ctx.block_delegation = True
            ctx.response = 'Max delegation depth exceeded'
        else:
            self.delegation_depth += 1
            ctx.proceed()

        # Reset on agent completion
        if ctx.agent_completed:
            self.delegation_depth = max(0, self.delegation_depth - 1)

@before_agent_callback
def prune_session_state(ctx):
    if len(ctx.session.messages) > 100:
        # Keep only last 20 tool responses
        tool_msgs = [m for m in ctx.session.messages 
                    if hasattr(m, 'tool_response')][-20:]
        # Keep recent conversation
        recent_msgs = ctx.session.messages[-30:]
        ctx.session.messages = recent_msgs + tool_msgs
    ctx.session.cleanup()
